sys_script.script:
(function executeRule(current, previous) {
    var club = new GlideRecord('x_2097092_linq_club');
    if (club.get(current.getValue('club'))) {
        if (club.getValue('status') !== 'active') {
            gs.addErrorMessage('Cannot create event: Club is not active.');
            current.setAbortAction(true);
            return;
        }
        var college = new GlideRecord('x_2097092_linq_college');
        if (college.get(club.getValue('college'))) {
            if (college.getValue('status') !== 'verified') {
                gs.addErrorMessage('Cannot create event: College is not verified.');
                current.setAbortAction(true);
                return;
            }
        }
    }
})(current, previous);
